class Solution {
    public boolean haveConflict(String[] event1, String[] event2) {
        String[] start = new String[] {event1[0], event2[0]};
        String[] end = new String[] {event1[1], event2[1]};
        Arrays.sort(start);
        Arrays.sort(end);
        return start[0].compareTo(end[0]) < 1;
    }
}
